/**
 * Real BFF API calls for Settings endpoints.
 * Routes: GET/PUT /settings/user, GET/PUT /settings/system
 */

import { apiClient } from '../api';
import { getAuthToken } from '@linm-soft-org/linm-web-common-components';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import type {
  UserSettings,
  SystemSettings,
  ChangePasswordRequest,
  ProfileSettings,
  NotificationSettings,
  DisplaySettings,
  SecuritySettings,
  PrivacySettings,
} from '../../models/Settings';
import type { BffUserSettingsDto, BffSystemSettingsDto } from './responseModel';

/** Map a BFF DTO to the frontend UserSettings model */
function mapUserSettings(dto: BffUserSettingsDto): UserSettings {
  return {
    userId: dto.userId,
    profile: {
      fullName:      dto.profile.fullName,
      email:         dto.profile.email ?? undefined,  // null → undefined
      emailVerified: dto.profile.emailVerified,
      phone:         dto.profile.phone,
      bio:           dto.profile.bio,
      avatar:        dto.profile.avatar,
      position:      dto.profile.position,
      department:    dto.profile.department,
    },
    notifications: dto.notifications as unknown as UserSettings['notifications'],
    display:       dto.display       as unknown as UserSettings['display'],
    security: {
      twoFactorEnabled:   dto.security.twoFactorEnabled,
      sessionTimeout:     dto.security.sessionTimeout,
      lastPasswordChange: dto.security.lastPasswordChange,
      passwordExpiryDays: dto.security.passwordExpiryDays,
    },
    privacy: {
      profileVisibility:   dto.privacy.profileVisibility as UserSettings['privacy']['profileVisibility'],
      showOnlineStatus:    dto.privacy.showOnlineStatus,
      showEmail:           dto.privacy.showEmail,
      showPhone:           dto.privacy.showPhone,
      allowDataCollection: dto.privacy.allowDataCollection,
      allowAnalytics:      dto.privacy.allowAnalytics,
    },
    createdAt: dto.createdAt,
    updatedAt: dto.updatedAt,
  };
}

/** Map BFF system DTO loosely to frontend SystemSettings */
function mapSystemSettings(dto: BffSystemSettingsDto): SystemSettings {
  return dto as unknown as SystemSettings;
}

export const settingsEndpoint = {
  /** GET /settings/user */
  getUserSettings: async (): Promise<UserSettings> => {
    const res = await apiClient.get<BffResponse<BffUserSettingsDto>>('/settings/user');
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user */
  updateUserSettings: async (settings: Partial<UserSettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user', settings);
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user/profile */
  updateProfile: async (profile: Partial<ProfileSettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user/profile', profile);
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user/notifications */
  updateNotifications: async (notifications: Partial<NotificationSettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user/notifications', notifications);
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user/display */
  updateDisplay: async (display: Partial<DisplaySettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user/display', display);
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user/security */
  updateSecurity: async (security: Partial<SecuritySettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user/security', security);
    return mapUserSettings(unwrap(res));
  },

  /** PUT /settings/user/privacy */
  updatePrivacy: async (privacy: Partial<PrivacySettings>): Promise<UserSettings> => {
    const res = await apiClient.put<BffResponse<BffUserSettingsDto>>('/settings/user/privacy', privacy);
    return mapUserSettings(unwrap(res));
  },

  /** POST /settings/user/change-password */
  changePassword: (request: ChangePasswordRequest): Promise<{ success: boolean; message: string }> =>
    apiClient.post<{ success: boolean; message: string }>('/settings/user/change-password', request),

  /** POST /settings/user/avatar  (multipart) */
  uploadAvatar: async (file: File): Promise<{ url: string }> => {
    const token = getAuthToken();
    const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5010/web-bff/api/v1';
    const formData = new FormData();
    formData.append('avatar', file);
    const res = await fetch(`${API_BASE_URL}/settings/user/avatar`, {
      method: 'POST',
      headers: token ? { Authorization: `Bearer ${token}` } : {},
      body: formData,
    });
    if (!res.ok) throw new Error('Tải ảnh lên thất bại');
    return res.json() as Promise<{ url: string }>;
  },

  /** POST /settings/user/verify-email */
  requestEmailVerification: (email: string): Promise<{ success: boolean; message: string }> =>
    apiClient.post<{ success: boolean; message: string }>('/settings/user/verify-email', { email }),

  /** GET /settings/user/export */
  exportUserData: async (): Promise<Blob> => {
    const token = getAuthToken();
    const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5010/web-bff/api/v1';
    const res = await fetch(`${API_BASE_URL}/settings/user/export`, {
      headers: token ? { Authorization: `Bearer ${token}` } : {},
    });
    if (!res.ok) throw new Error('Xuất dữ liệu thất bại');
    return res.blob();
  },

  /** GET /settings/system */
  getSystemSettings: async (): Promise<SystemSettings> => {
    const res = await apiClient.get<BffResponse<BffSystemSettingsDto>>('/settings/system');
    return mapSystemSettings(unwrap(res));
  },

  /** PUT /settings/system */
  updateSystemSettings: async (settings: Partial<SystemSettings>): Promise<SystemSettings> => {
    const res = await apiClient.put<BffResponse<BffSystemSettingsDto>>('/settings/system', settings);
    return mapSystemSettings(unwrap(res));
  },
};
