/**
 * NotificationsPage – Full-page notification centre.
 *
 * Features:
 *  - Server-side pagination (Pagination component in TableCard footer)
 *  - "Tất cả" / "Chưa đọc" tab filter
 *  - Mark single notification as read (click row)
 *  - Mark all as read
 *  - Delete single notification
 *  - Navigates to actionUrl on click
 *  - Real-time updates via SignalR (pushed to Redux)
 */
import React, { useCallback, useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch, useAppSelector } from '../../store/hooks';
import {
  markNotificationRead,
  markAllNotificationsRead,
  deleteNotification,
} from '../../store/slices/notificationSlice';
import type { NotificationDto } from '../../services/notifications';
import { NotificationType, notificationService } from '../../services/notifications';
import { TableCard } from '../../components/common/TableCard/TableCard';
import { Pagination } from '../../components/common/Pagination/Pagination';
import { Button } from '../../components/common/Button';
import { useMinLoadingTime } from '../../hooks/useMinLoadingTime';
import styles from './NotificationsPage.module.css';

// ── Constants ────────────────────────────────────────────────────────────────

const PAGE_SIZE = 20;

// ── Helpers ──────────────────────────────────────────────────────────────────

function relativeTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60_000);
  const hours = Math.floor(diff / 3_600_000);
  const days = Math.floor(diff / 86_400_000);
  if (mins < 1) return 'Vừa xong';
  if (mins < 60) return `${mins} phút trước`;
  if (hours < 24) return `${hours} giờ trước`;
  if (days < 7) return `${days} ngày trước`;
  return new Date(iso).toLocaleDateString('vi-VN');
}

function getIconClass(type: string): { icon: string; cls: string } {
  switch (type) {
    case NotificationType.TICKET_ASSIGNED:
    case NotificationType.TASK_ASSIGNED:
      return { icon: 'fas fa-user-check', cls: styles.typeAssigned };
    case NotificationType.TICKET_SUPPORT_ASSIGNED:
      return { icon: 'fas fa-hands-helping', cls: styles.typeAssigned };
    case NotificationType.TASK_COLLABORATOR_ASSIGNED:
      return { icon: 'fas fa-user-plus', cls: styles.typeAssigned };
    case NotificationType.TASK_REASSIGNED:
      return { icon: 'fas fa-exchange-alt', cls: styles.typeAssigned };
    case NotificationType.NEW_MESSAGE:
      return { icon: 'fas fa-comment-dots', cls: styles.typeMessage };
    case NotificationType.STATUS_CHANGED:
      return { icon: 'fas fa-exchange-alt', cls: styles.typeStatus };
    case NotificationType.APPROVAL_NEEDED:
      return { icon: 'fas fa-stamp', cls: styles.typeApproval };
    case NotificationType.SLA_WARNING:
    case NotificationType.SLA_BREACH:
      return { icon: 'fas fa-exclamation-circle', cls: styles.typeSla };
    case NotificationType.TICKET_CREATED_FOR_DEPT:
    case NotificationType.TASK_ASSIGNED_TO_DEPT:
      return { icon: 'fas fa-building', cls: styles.typeDefault };
    default:
      return { icon: 'fas fa-bell', cls: styles.typeDefault };
  }
}

// ── Component ────────────────────────────────────────────────────────────────

const NotificationsPage: React.FC = () => {
  useNavTitle('Thông báo');
  const dispatch = useAppDispatch();
  const navigate = useNavigate();

  const { unreadCount } = useAppSelector((s) => s.notifications);

  const [unreadOnly, setUnreadOnly] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const [pageItems, setPageItems] = useState<NotificationDto[]>([]);
  const [pageLoading, setPageLoading] = useState(true);
  const [fetchError, setFetchError] = useState<string | null>(null);

  const showLoading = useMinLoadingTime(pageLoading);

  // ── Fetch notifications with pagination ──────────────────────────────────
  const loadNotifications = useCallback(async () => {
    setPageLoading(true);
    setFetchError(null);
    try {
      const result = await notificationService.getNotifications(
        unreadOnly,
        currentPage,
        PAGE_SIZE,
      );
      setPageItems(result.items);
      setTotalCount(result.totalCount);
    } catch (err) {
      const msg =
        err instanceof TypeError && err.message === 'Failed to fetch'
          ? 'Không thể kết nối đến máy chủ. Vui lòng kiểm tra kết nối mạng hoặc thử lại sau.'
          : 'Đã xảy ra lỗi khi tải thông báo.';
      setFetchError(msg);
    } finally {
      setPageLoading(false);
    }
  }, [unreadOnly, currentPage]);

  useEffect(() => {
    loadNotifications();
  }, [loadNotifications]);

  // ── Tab change ────────────────────────────────────────────────────────────
  const handleTabChange = (isUnread: boolean) => {
    setUnreadOnly(isUnread);
    setCurrentPage(1);
  };

  // ── Click notification → mark read + navigate ─────────────────────────────
  const handleItemClick = useCallback(
    (notif: NotificationDto) => {
      if (!notif.isRead) {
        dispatch(markNotificationRead(notif.id));
        setPageItems((prev) =>
          prev.map((n) =>
            n.id === notif.id
              ? { ...n, isRead: true, readAt: new Date().toISOString() }
              : n,
          ),
        );
      }
      // NEW_MESSAGE → navigate to Messages Inbox for that entity
      if (notif.type === NotificationType.NEW_MESSAGE && notif.entityType && notif.entityId) {
        navigate(`/messages/${notif.entityType}/${notif.entityId}`);
        return;
      }
      if (notif.actionUrl) {
        navigate(notif.actionUrl);
      }
    },
    [dispatch, navigate],
  );

  // ── Mark all read ─────────────────────────────────────────────────────────
  const handleMarkAllRead = useCallback(async () => {
    await dispatch(markAllNotificationsRead());
    loadNotifications();
  }, [dispatch, loadNotifications]);

  // ── Delete single ─────────────────────────────────────────────────────────
  const handleDelete = useCallback(
    async (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      await dispatch(deleteNotification(id));
      setPageItems((prev) => prev.filter((n) => n.id !== id));
      setTotalCount((prev) => Math.max(0, prev - 1));
    },
    [dispatch],
  );

  // ── Pagination ────────────────────────────────────────────────────────────
  const totalPages = Math.ceil(totalCount / PAGE_SIZE);

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div className={styles.page}>
      {/* Page header */}
      <div className={styles.pageHeader}>
        <div className={styles.headerLeft}>
          <h1 className={styles.pageTitle}>
            <i className="fas fa-bell" /> Thông báo
          </h1>
          {unreadCount > 0 && (
            <span className={styles.unreadBadge}>{unreadCount} chưa đọc</span>
          )}
        </div>
        <div className={styles.headerActions}>
          <Button
            variant="secondary"
            size="sm"
            onClick={handleMarkAllRead}
            disabled={unreadCount === 0}
          >
            <i className="fas fa-check-double" /> Đọc tất cả
          </Button>
        </div>
      </div>

      {/* TableCard */}
      <TableCard
        header={
          <div className={styles.tabs} role="tablist">
            <button
              role="tab"
              aria-selected={!unreadOnly}
              className={`${styles.tab} ${!unreadOnly ? styles.activeTab : ''}`}
              onClick={() => handleTabChange(false)}
            >
              <i className="fas fa-list" /> Tất cả
              {totalCount > 0 && !unreadOnly && (
                <span className={styles.tabBadge}>{totalCount}</span>
              )}
            </button>
            <button
              role="tab"
              aria-selected={unreadOnly}
              className={`${styles.tab} ${unreadOnly ? styles.activeTab : ''}`}
              onClick={() => handleTabChange(true)}
            >
              <i className="fas fa-envelope" /> Chưa đọc
              {unreadCount > 0 && (
                <span className={styles.tabBadgeUnread}>{unreadCount}</span>
              )}
            </button>
          </div>
        }
        footer={
          !showLoading && pageItems.length > 0 && totalPages > 1 ? (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          ) : undefined
        }
      >
        {/* Loading skeleton */}
        {showLoading && (
          <div className={styles.skeletonList}>
            {Array.from({ length: 6 }).map((_, i) => (
              <div key={i} className={styles.skeletonItem}>
                <div className={styles.skeletonIcon} />
                <div className={styles.skeletonBody}>
                  <div className={styles.skeletonTitle} />
                  <div className={styles.skeletonMessage} />
                  <div className={styles.skeletonMeta} />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Error state */}
        {!showLoading && fetchError && (
          <div className={styles.errorState}>
            <i className="fas fa-exclamation-triangle" />
            <h3>Lỗi kết nối</h3>
            <p>{fetchError}</p>
            <Button variant="primary" size="sm" onClick={loadNotifications}>
              <i className="fas fa-redo" /> Thử lại
            </Button>
          </div>
        )}

        {/* Empty state */}
        {!showLoading && !fetchError && pageItems.length === 0 && (
          <div className={styles.empty}>
            <i className="fas fa-bell-slash" />
            <h3>{unreadOnly ? 'Không có thông báo chưa đọc' : 'Không có thông báo nào'}</h3>
            <p>
              {unreadOnly
                ? 'Tất cả thông báo đã được đọc.'
                : 'Bạn chưa nhận được thông báo nào.'}
            </p>
          </div>
        )}

        {/* Notification list */}
        {!showLoading && !fetchError && pageItems.length > 0 && (
          <div className={styles.list} role="list">
            {pageItems.map((notif) => {
              const { icon, cls } = getIconClass(notif.type);
              return (
                <div
                  key={notif.id}
                  role="listitem"
                  className={`${styles.item} ${!notif.isRead ? styles.unread : ''}`}
                  onClick={() => handleItemClick(notif)}
                >
                  <div className={`${styles.iconWrap} ${cls}`}>
                    <i className={icon} />
                  </div>

                  <div className={styles.body}>
                    <div className={styles.itemHeader}>
                      <p className={styles.itemTitle}>{notif.title}</p>
                      <span className={styles.time}>{relativeTime(notif.createdAt)}</span>
                    </div>
                    <p className={styles.itemMessage}>{notif.message}</p>
                  </div>

                  <div className={styles.itemActions}>
                    {!notif.isRead && <span className={styles.unreadDot} title="Chưa đọc" />}
                    <button
                      type="button"
                      aria-label="Xóa thông báo"
                      className={styles.deleteBtn}
                      onClick={(e) => handleDelete(e, notif.id)}
                    >
                      <i className="fas fa-trash-alt" />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </TableCard>
    </div>
  );
};

export default NotificationsPage;
