import React, { createContext, useContext, useState, useCallback } from 'react';
import { createPortal } from 'react-dom';
import styles from './Alert.module.css';

export type AlertType = 'info' | 'success' | 'warning' | 'error' | 'confirm';

export interface AlertButton {
  label: string;
  onClick: () => void;
  variant?: 'primary' | 'secondary' | 'danger';
}

export interface AlertOptions {
  title?: string;
  message: string;
  type?: AlertType;
  buttons?: AlertButton[];
  onClose?: () => void;
}

interface AlertContextType {
  showAlert: (options: AlertOptions) => void;
  confirm: (message: string, onConfirm: () => void, onCancel?: () => void) => void;
  info: (message: string, title?: string) => void;
  success: (message: string, title?: string) => void;
  warning: (message: string, title?: string) => void;
  error: (message: string, title?: string) => void;
}

const AlertContext = createContext<AlertContextType | undefined>(undefined);

export const useAlert = () => {
  const context = useContext(AlertContext);
  if (!context) {
    throw new Error('useAlert must be used within AlertProvider');
  }
  return context;
};

interface AlertState extends AlertOptions {
  id: string;
  isOpen: boolean;
}

export const AlertProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [alert, setAlert] = useState<AlertState | null>(null);

  const closeAlert = useCallback(() => {
    if (alert?.onClose) {
      alert.onClose();
    }
    setAlert(null);
  }, [alert]);

  const showAlert = useCallback((options: AlertOptions) => {
    const id = `alert-${Date.now()}-${Math.random()}`;
    setAlert({
      ...options,
      id,
      isOpen: true,
    });
  }, []);

  const confirm = useCallback(
    (message: string, onConfirm: () => void, onCancel?: () => void) => {
      showAlert({
        message,
        type: 'confirm',
        title: 'Xác nhận',
        buttons: [
          {
            label: 'Hủy',
            onClick: () => {
              if (onCancel) onCancel();
              closeAlert();
            },
            variant: 'secondary',
          },
          {
            label: 'Xác nhận',
            onClick: () => {
              onConfirm();
              closeAlert();
            },
            variant: 'primary',
          },
        ],
      });
    },
    [showAlert, closeAlert]
  );

  const info = useCallback(
    (message: string, title?: string) => {
      showAlert({
        message,
        type: 'info',
        title: title || 'Thông báo',
        buttons: [
          {
            label: 'Đóng',
            onClick: closeAlert,
            variant: 'primary',
          },
        ],
      });
    },
    [showAlert, closeAlert]
  );

  const success = useCallback(
    (message: string, title?: string) => {
      showAlert({
        message,
        type: 'success',
        title: title || 'Thành công',
        buttons: [
          {
            label: 'Đóng',
            onClick: closeAlert,
            variant: 'primary',
          },
        ],
      });
    },
    [showAlert, closeAlert]
  );

  const warning = useCallback(
    (message: string, title?: string) => {
      showAlert({
        message,
        type: 'warning',
        title: title || 'Cảnh báo',
        buttons: [
          {
            label: 'Đóng',
            onClick: closeAlert,
            variant: 'primary',
          },
        ],
      });
    },
    [showAlert, closeAlert]
  );

  const error = useCallback(
    (message: string, title?: string) => {
      showAlert({
        message,
        type: 'error',
        title: title || 'Lỗi',
        buttons: [
          {
            label: 'Đóng',
            onClick: closeAlert,
            variant: 'primary',
          },
        ],
      });
    },
    [showAlert, closeAlert]
  );

  const getIcon = (type: AlertType) => {
    switch (type) {
      case 'success':
        return 'fas fa-check-circle';
      case 'error':
        return 'fas fa-times-circle';
      case 'warning':
        return 'fas fa-exclamation-triangle';
      case 'confirm':
        return 'fas fa-question-circle';
      case 'info':
      default:
        return 'fas fa-info-circle';
    }
  };

  return (
    <AlertContext.Provider value={{ showAlert, confirm, info, success, warning, error }}>
      {children}
      {alert?.isOpen &&
        createPortal(
          <div className={styles.overlay} onClick={closeAlert}>
            <div
              className={`${styles.alert} ${styles[alert.type || 'info']}`}
              onClick={(e) => e.stopPropagation()}
            >
              <div className={styles.icon}>
                <i className={getIcon(alert.type || 'info')}></i>
              </div>
              <div className={styles.content}>
                {alert.title && <h3 className={styles.title}>{alert.title}</h3>}
                <p className={styles.message}>{alert.message}</p>
              </div>
              <div className={styles.buttons}>
                {alert.buttons?.map((button, index) => (
                  <button
                    key={index}
                    className={`${styles.button} ${styles[button.variant || 'primary']}`}
                    onClick={button.onClick}
                  >
                    {button.label}
                  </button>
                ))}
              </div>
            </div>
          </div>,
          document.body
        )}
    </AlertContext.Provider>
  );
};
