import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAppSelector } from '../../store/hooks';
import { getHomePath, hasValidAuthToken, isPermissionsReady } from '@linm-soft-org/linm-web-common-components';

interface PublicRouteProps {
  /** Route chỉ dành cho người chưa đăng nhập.
   *  Nếu đã xác thực → redirect về trang gốc (state.from) hoặc mặc định /dashboard */
  children: React.ReactNode;
  /** Đường dẫn fallback khi đã đăng nhập; nếu user có defaultMenuUrl thì ưu tiên đó */
  redirectTo?: string;
}

/**
 * PublicRoute — bảo vệ các route công khai (login, register, …).
 *
 * Logic:
 *  - Chưa đăng nhập  → hiển thị children bình thường
 *  - Đã đăng nhập    → redirect tới trang home của user (defaultMenuUrl > role-based > redirectTo)
 */
export const PublicRoute: React.FC<PublicRouteProps> = ({
  children,
}) => {
  const { isAuthenticated, user } = useAppSelector((state) => state.auth);
  const location = useLocation();

  // Guard against stale module-cache state: store says authenticated but
  // auth_token was cleared (e.g. by Task's logout before a hard reload, or
  // manual localStorage.clear). Treat as unauthenticated so the login form shows.
  const tokenExists = hasValidAuthToken();

  if (isAuthenticated && tokenExists) {
    // Nếu trước đó bị redirect từ một trang cụ thể, quay về trang đó
    const from =
      (location.state as { from?: Location })?.from?.pathname;

    const destination =
      user?.defaultMenuUrl
      || from
      || (isPermissionsReady()
        ? getHomePath(user?.role, user?.package, undefined, user?.packageDefaultUrl)
        : '/');

    return <Navigate to={destination} replace />;
  }

  return <>{children}</>;
};
