import React from 'react';
import { HelpCategory, getAllCategories } from '../../../models/Help';
import styles from './FAQCategoryFilter.module.css';

interface FAQCategoryFilterProps {
  selectedCategory?: HelpCategory;
  onCategoryChange: (category?: HelpCategory) => void;
}

export const FAQCategoryFilter: React.FC<FAQCategoryFilterProps> = ({
  selectedCategory,
  onCategoryChange,
}) => {
  const categories = getAllCategories();

  return (
    <div className={styles.filter}>
      <button
        className={`${styles.filterButton} ${
          !selectedCategory ? styles.active : ''
        }`}
        onClick={() => onCategoryChange(undefined)}
      >
        Tất cả
      </button>
      {categories.map((category) => (
        <button
          key={category.id}
          className={`${styles.filterButton} ${
            selectedCategory === category.id ? styles.active : ''
          }`}
          onClick={() => onCategoryChange(category.id as HelpCategory)}
        >
          <i className={category.icon} />
          <span>{category.label}</span>
        </button>
      ))}
    </div>
  );
};
