import React, { useEffect, useMemo, useState } from 'react';
import {
  SearchInput,
  Select,
  filterActiveCompaniesForUser,
  resolveUserCompanyScope,
} from '@linm-soft-org/linm-web-common-components';
import { companyService, type ActiveCompanyItem } from '../../services/companyService';
import { createAdminAccountSearchConfig } from '../../components/search/createAdminAccountSearchConfig';
import type { AdminAccountListItem } from '../../services/admin';
import {
  defaultCompanyAccountSearchFormData,
  type CompanyAccountSearchFormData,
} from '../../types/companyAccountSearch';
import { useAppSelector } from '../../store/hooks';
import { formatCompanyOptionLabel } from '../../utils/formatCompanyOptionLabel';
import { getAccountRoleLabel } from '../../utils/accountRoleLabels';
import styles from './CompanyAccountSearchPage.module.css';

export interface CompanyAccountSearchFormProps {
  initialData?: CompanyAccountSearchFormData;
  onAccountSelect?: (account: AdminAccountListItem | null) => void;
}

export const CompanyAccountSearchForm: React.FC<CompanyAccountSearchFormProps> = ({
  initialData,
  onAccountSelect,
}) => {
  const [form, setForm] = useState<CompanyAccountSearchFormData>(
    initialData ?? defaultCompanyAccountSearchFormData,
  );
  const [companies, setCompanies] = useState<ActiveCompanyItem[]>([]);
  const [companiesLoading, setCompaniesLoading] = useState(true);
  const user = useAppSelector((state) => state.auth.user);

  const scopedCompanies = useMemo(() => {
    if (!companies.length) return [];
    const scope = resolveUserCompanyScope(user);
    return filterActiveCompaniesForUser(
      companies,
      scope.canViewAllCompanies,
      scope.allowedCompanyIds,
      scope.homeCompanyId,
    );
  }, [companies, user]);

  const showCompanyPicker = scopedCompanies.length > 1;

  const resolvedCompanyId =
    form.companyId
    || (scopedCompanies.length === 1 ? scopedCompanies[0]?.id : undefined)
    || user?.companyId
    || undefined;

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      companyService
        .getActiveList()
        .then((items) => {
          if (!cancelled) setCompanies(items);
        })
        .catch(() => {
          if (!cancelled) setCompanies([]);
        })
        .finally(() => {
          if (!cancelled) setCompaniesLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, []);

  useEffect(() => {
    if (companiesLoading || scopedCompanies.length !== 1) return;
    const onlyId = scopedCompanies[0]?.id;
    if (!onlyId || form.companyId === onlyId) return;

    const timer = setTimeout(() => {
      setForm({ ...defaultCompanyAccountSearchFormData, companyId: onlyId });
      onAccountSelect?.(null);
    }, 0);
    return () => clearTimeout(timer);
  }, [companiesLoading, scopedCompanies, form.companyId, onAccountSelect]);

  const companyOptions = useMemo(
    () => [
      { value: '', label: '— Chọn công ty —' },
      ...scopedCompanies.map((c) => ({
        value: c.id,
        label: formatCompanyOptionLabel(c),
      })),
    ],
    [scopedCompanies],
  );

  const accountSearchConfig = useMemo(
    () => createAdminAccountSearchConfig(resolvedCompanyId),
    [resolvedCompanyId],
  );

  const handleCompanyChange = (value: string) => {
    setForm({
      ...defaultCompanyAccountSearchFormData,
      companyId: value,
    });
    onAccountSelect?.(null);
  };

  const handleAccountChange = (item: AdminAccountListItem) => {
    setForm((prev) => ({
      ...prev,
      accountId: item.id,
      username: item.username,
      fullName: item.fullName,
      email: item.email,
      role: item.role,
    }));
    onAccountSelect?.(item);
  };

  const handleAccountClear = () => {
    setForm((prev) => ({
      ...prev,
      accountId: '',
      username: '',
      fullName: '',
      email: '',
      role: '',
    }));
    onAccountSelect?.(null);
  };

  const accountSearchDisabled = !resolvedCompanyId || companiesLoading;

  return (
    <div className={styles.form} data-testid="home-account-search-form">
      {showCompanyPicker && (
        <div className={styles.section}>
          <h2 className={styles.sectionTitle}>Chọn công ty</h2>
          <div className={styles.row2}>
            <Select
              label="Công ty"
              value={form.companyId}
              onChange={(e) => handleCompanyChange(e.target.value)}
              options={companyOptions}
              fullWidth
              disabled={companiesLoading}
              data-testid="home-account-search-field-company"
            />
          </div>
          {!form.companyId && !companiesLoading && (
            <p className={styles.hint}>
              Chọn đơn vị cơ sở để lọc tài khoản thuộc công ty đó.
            </p>
          )}
        </div>
      )}

      <div className={styles.section}>
        <h2 className={styles.sectionTitle}>Tìm tài khoản</h2>
        <div className={styles.formCell}>
          <label className={styles.fieldLabel}>Tài khoản người dùng</label>
          <SearchInput
            config={accountSearchConfig}
            value={form.accountId}
            primaryDisplay={form.username}
            secondaryDisplay={form.fullName}
            showLabel={false}
            placeholder="Tìm theo username, họ tên, email..."
            showSecondaryInput
            disabled={accountSearchDisabled}
            className={styles.accountSearchField}
            onChange={handleAccountChange}
            onClear={handleAccountClear}
            data-testid="home-account-search-field-account"
          />
        </div>
      </div>

      {form.accountId && (
        <div className={styles.section} data-testid="home-account-search-preview">
          <h2 className={styles.sectionTitle}>Tài khoản đã chọn</h2>
          <dl className={styles.previewGrid}>
            <div>
              <dt>Username</dt>
              <dd>@{form.username}</dd>
            </div>
            <div>
              <dt>Họ và tên</dt>
              <dd>{form.fullName || '—'}</dd>
            </div>
            <div>
              <dt>Email</dt>
              <dd>{form.email || '—'}</dd>
            </div>
            <div>
              <dt>Vai trò</dt>
              <dd>{getAccountRoleLabel(form.role)}</dd>
            </div>
          </dl>
        </div>
      )}
    </div>
  );
};
