import React, { useEffect, useRef } from 'react';
import type { Parcel } from 'single-spa';
import {
  mountParcel,
  unmountParcel,
  MESSAGES_INBOX_PARCEL,
} from '@linm-soft-org/linm-web-common-components';

export interface MessagesPageParcelHostProps {
  entityType?: string;
  entityId?: string;
  onNavigate: (path: string) => void;
}

/** Host /messages route via @linm/message parcel (single source of truth). */
export const MessagesPageParcelHost: React.FC<MessagesPageParcelHostProps> = ({
  entityType,
  entityId,
  onNavigate,
}) => {
  const hostRef = useRef<HTMLDivElement>(null);
  const parcelRef = useRef<Parcel | null>(null);
  const onNavigateRef = useRef(onNavigate);
  onNavigateRef.current = onNavigate;

  useEffect(() => {
    let cancelled = false;
    const host = hostRef.current;
    if (!host) return;

    const timer = setTimeout(() => {
      mountParcel({
        link: MESSAGES_INBOX_PARCEL,
        domElement: host,
        customProps: {
          entityType,
          entityId,
          onNavigate: (path: string) => onNavigateRef.current(path),
        },
      })
        .then((p) => {
          if (cancelled) {
            void unmountParcel(p);
            return;
          }
          parcelRef.current = p;
        })
        .catch((err) => {
          console.warn('[MessagesPageParcelHost]', err);
        });
    }, 0);

    return () => {
      cancelled = true;
      clearTimeout(timer);
      void unmountParcel(parcelRef.current);
      parcelRef.current = null;
    };
  }, [entityType, entityId]);

  return <div ref={hostRef} style={{ height: '100%' }} />;
};
