import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft-org/linm-web-common-components';
import { useAppToast } from '../../hooks/useAppToast';
import { HelpSearchResult } from '../../models/Help';
import { helpService } from '../../services/helpService';
import { Button } from '../../components/common/Button';
import { SearchBar } from '../../components/help/SearchBar';
import { QuickLinks } from '../../components/help/QuickLinks';
import { ContactSupportPanel } from '../../components/help/ContactSupportPanel';
import styles from './HelpCenterPage.module.css';

export const HelpCenterPage: React.FC = () => {
  useNavTitle('Trung tâm Trợ giúp');
  const navigate = useNavigate();
  const toast = useAppToast();
  const [searchResults, setSearchResults] = useState<HelpSearchResult[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searching, setSearching] = useState(false);
  const [contactPanelOpen, setContactPanelOpen] = useState(false);

  const handleSearch = async (query: string) => {
    setSearchQuery(query);
    
    if (!query || query.length < 2) {
      setSearchResults([]);
      return;
    }

    try {
      setSearching(true);
      const results = await helpService.search(query);
      setSearchResults(results);
    } catch (error: unknown) {
      toast.fromError(error, 'Không thể tìm kiếm, vui lòng thử lại');
    } finally {
      setSearching(false);
    }
  };

  const handleResultClick = (result: HelpSearchResult) => {
    navigate(result.url);
    setSearchQuery('');
    setSearchResults([]);
  };

  return (
    <div className={styles.helpCenter}>
      {/* Hero Section */}
      <div className={styles.hero}>
        <h1 className={styles.heroTitle}>Trung tâm Trợ giúp</h1>
        <p className={styles.heroSubtitle}>
          Tìm câu trả lời cho các câu hỏi của bạn
        </p>
        
        <div className={styles.heroSearch}>
          <SearchBar
            value={searchQuery}
            onChange={handleSearch}
            searching={searching}
            results={searchResults}
            onResultClick={handleResultClick}
          />
        </div>
      </div>

      {/* Quick Links */}
      <QuickLinks onContactClick={() => setContactPanelOpen(true)} />

      {/* Categories Grid */}
      {/* <section className={styles.section}>
        <h2 className={styles.sectionTitle}>Danh mục</h2>
        <CategoryGrid categories={categories} />
      </section> */}

      {/* Featured Articles */}
      {/* {featuredArticles.length > 0 && (
        <section className={styles.section}>
          <h2 className={styles.sectionTitle}>Bài viết nổi bật</h2>
          <FeaturedArticles articles={featuredArticles} />
        </section>
      )} */}

      {/* Still Need Help */}
      <section className={styles.contactSection}>
        <h2>Vẫn cần trợ giúp?</h2>
        <p>Liên hệ với đội ngũ hỗ trợ của chúng tôi</p>
        <Button
          variant="primary"
          size="lg"
          onClick={() => setContactPanelOpen(true)}
        >
          <i className="fas fa-headset"></i>
          &nbsp;Gửi yêu cầu hỗ trợ
        </Button>
      </section>

      {/* Contact Support Panel */}
      <ContactSupportPanel
        isOpen={contactPanelOpen}
        onClose={() => setContactPanelOpen(false)}
      />
    </div>
  );
};
