/**
 * Settings service facade.
 */

import {
  UserSettings,
  SystemSettings,
  ChangePasswordRequest,
  ProfileSettings,
  NotificationSettings,
  DisplaySettings,
  SecuritySettings,
  PrivacySettings,
} from '../../models/Settings';
import { settingsEndpoint } from './endpoint';

export const settingsService = {
  getUserSettings: (_userId?: string): Promise<UserSettings> =>
    settingsEndpoint.getUserSettings(),

  updateUserSettings: (settings: Partial<UserSettings>): Promise<UserSettings> =>
    settingsEndpoint.updateUserSettings(settings),

  updateProfile: (profile: Partial<ProfileSettings>): Promise<UserSettings> =>
    settingsEndpoint.updateProfile(profile),

  updateNotifications: (notifications: Partial<NotificationSettings>): Promise<UserSettings> =>
    settingsEndpoint.updateNotifications(notifications),

  updateDisplay: (display: Partial<DisplaySettings>): Promise<UserSettings> =>
    settingsEndpoint.updateDisplay(display),

  updateSecurity: (security: Partial<SecuritySettings>): Promise<UserSettings> =>
    settingsEndpoint.updateSecurity(security),

  updatePrivacy: (privacy: Partial<PrivacySettings>): Promise<UserSettings> =>
    settingsEndpoint.updatePrivacy(privacy),

  changePassword: (request: ChangePasswordRequest): Promise<{ success: boolean; message: string }> =>
    settingsEndpoint.changePassword(request),

  uploadAvatar: (file: File): Promise<{ url: string }> =>
    settingsEndpoint.uploadAvatar(file),

  requestEmailVerification: (email: string): Promise<{ success: boolean; message: string }> =>
    settingsEndpoint.requestEmailVerification(email),

  exportUserData: (): Promise<Blob> => settingsEndpoint.exportUserData(),

  getSystemSettings: (): Promise<SystemSettings> => settingsEndpoint.getSystemSettings(),

  updateSystemSettings: (settings: Partial<SystemSettings>): Promise<SystemSettings> =>
    settingsEndpoint.updateSystemSettings(settings),
};
