import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import type {
  AdminAccountDetail,
  AdminAccountListItem,
  AdminAccountsPagedResult,
  GetAdminAccountsRequest,
} from './accountTypes';

function normalizeListItem(raw: Record<string, unknown>): AdminAccountListItem {
  const roles = Array.isArray(raw.roles) ? raw.roles : [];
  const role = String(raw.role ?? roles[0] ?? '').toLowerCase();
  const status = String(raw.status ?? '').toLowerCase();
  return {
    id: String(raw.id),
    username: String(raw.username ?? raw.userName ?? raw.user_name ?? ''),
    fullName: String(raw.fullName ?? raw.full_name ?? ''),
    email: String(raw.email ?? ''),
    role: role || 'staff',
    status: String(raw.status ?? ''),
    isDeleted: raw.isDeleted === true || status === 'deleted',
    isActive: raw.isActive === true || (!status || status === 'active'),
    isEmailConfirmed: raw.isEmailConfirmed === true,
    createdAt: String(raw.createdAt ?? ''),
    activePackageCount:
      Number(raw.activePackageCount ?? (raw.packages as unknown[] | undefined)?.length ?? 0),
  };
}

function normalizeDetail(raw: Record<string, unknown>): AdminAccountDetail {
  const base = normalizeListItem(raw);
  return {
    ...base,
    phone: raw.phone ? String(raw.phone) : null,
    companyId: raw.companyId ? String(raw.companyId) : null,
    packages: Array.isArray(raw.packages) ? raw.packages : [],
  };
}

export const accountsEndpoint = {
  getAccounts: async (
    params: GetAdminAccountsRequest = {},
  ): Promise<AdminAccountsPagedResult> => {
    const qs = new URLSearchParams();
    if (params.search) qs.set('search', params.search);
    if (params.status) qs.set('status', params.status);
    if (params.role) qs.set('role', params.role);
    if (params.companyId) qs.set('companyId', params.companyId);
    if (params.page !== undefined) qs.set('page', String(params.page));
    if (params.pageSize !== undefined) qs.set('pageSize', String(params.pageSize));
    const query = qs.toString() ? `?${qs}` : '';
    const res = await apiClient.get<BffResponse<AdminAccountsPagedResult>>(
      `/admin/accounts${query}`,
    );
    const data = unwrap(res);
    return {
      ...data,
      items: (data.items ?? []).map((item) =>
        normalizeListItem(item as unknown as Record<string, unknown>),
      ),
    };
  },

  getAccountDetail: async (id: string): Promise<AdminAccountDetail> => {
    const res = await apiClient.get<BffResponse<Record<string, unknown>>>(
      `/admin/accounts/${id}`,
    );
    return normalizeDetail(unwrap(res));
  },
};
