/**
 * Real BFF API calls for Help endpoints.
 * Routes: GET /help/articles, /help/faqs, /help/workflows, etc.
 */

import { apiClient } from '../api';
import { unwrap } from '../shared/bffEnvelope';
import type { BffResponse } from '../shared/bffEnvelope';
import type {
  HelpArticle,
  FAQ,
  Workflow,
  VideoTutorial,
  HelpCategory,
  HelpCategoryInfo,
  HelpSearchResult,
  ArticleFeedback,
  SupportTicket,
  SupportTicketCreate,
} from '../../models/Help';

export const helpEndpoint = {
  /** GET /help/articles?category=&featured= */
  getArticles: async (category?: HelpCategory, featured?: boolean): Promise<HelpArticle[]> => {
    const params = new URLSearchParams();
    if (category) params.set('category', category);
    if (featured !== undefined) params.set('featured', String(featured));
    const qs = params.toString();
    const res = await apiClient.get<BffResponse<HelpArticle[]>>(`/help/articles${qs ? `?${qs}` : ''}`);
    return unwrap(res);
  },

  /** GET /help/articles/:slug */
  getArticle: async (slug: string): Promise<HelpArticle> => {
    const res = await apiClient.get<BffResponse<HelpArticle>>(`/help/articles/${slug}`);
    return unwrap(res);
  },

  /** POST /help/feedback */
  submitFeedback: async (feedback: ArticleFeedback): Promise<void> => {
    await apiClient.post<BffResponse<object>>('/help/feedback', feedback);
  },

  /** GET /help/search?q= */
  search: async (query: string): Promise<HelpSearchResult[]> => {
    const res = await apiClient.get<BffResponse<HelpSearchResult[]>>(`/help/search?q=${encodeURIComponent(query)}`);
    return unwrap(res);
  },

  /** GET /help/faqs?category= */
  getFAQs: async (category?: HelpCategory): Promise<FAQ[]> => {
    const qs = category ? `?category=${category}` : '';
    const res = await apiClient.get<BffResponse<FAQ[]>>(`/help/faqs${qs}`);
    return unwrap(res);
  },

  /** GET /help/workflows */
  getWorkflows: async (): Promise<Workflow[]> => {
    const res = await apiClient.get<BffResponse<Workflow[]>>('/help/workflows');
    return unwrap(res);
  },

  /** GET /help/workflows/:type */
  getWorkflow: async (type: 'ticket' | 'task' | 'incident'): Promise<Workflow> => {
    const res = await apiClient.get<BffResponse<Workflow>>(`/help/workflows/${type}`);
    return unwrap(res);
  },

  /** GET /help/videos?category= */
  getVideos: async (category?: HelpCategory): Promise<VideoTutorial[]> => {
    const qs = category ? `?category=${category}` : '';
    const res = await apiClient.get<BffResponse<VideoTutorial[]>>(`/help/videos${qs}`);
    return unwrap(res);
  },

  /** GET /help/categories */
  getCategories: async (): Promise<HelpCategoryInfo[]> => {
    const res = await apiClient.get<BffResponse<HelpCategoryInfo[]>>('/help/categories');
    return unwrap(res);
  },

  /** POST /help/support-ticket */
  submitSupportTicket: async (ticket: SupportTicketCreate): Promise<SupportTicket> => {
    const res = await apiClient.post<BffResponse<SupportTicket>>('/help/support-ticket', ticket);
    return unwrap(res);
  },
};
