import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft-org/linm-web-common-components';
import { SupportTicketCreate } from '../../models/Help';
import { helpService } from '../../services/helpService';
import { ContactForm } from '../../components/help/ContactForm';
import { useAlert } from '../../components/common/Alert';
import { useAppToast } from '../../hooks/useAppToast';
import styles from './ContactPage.module.css';

export const ContactPage: React.FC = () => {
  useNavTitle('Liên hệ Hỗ trợ');
  const navigate = useNavigate();
  const alert = useAlert();
  const toast = useAppToast();
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async (ticket: SupportTicketCreate) => {
    try {
      setSubmitting(true);
      const result = await helpService.submitSupportTicket(ticket);
      console.log('Support ticket created:', result);
      setSubmitted(true);
    } catch (error: unknown) {
      toast.fromError(error, 'Không thể gửi yêu cầu hỗ trợ. Vui lòng thử lại.');
      alert.error('Không thể gửi yêu cầu hỗ trợ. Vui lòng thử lại.');
    } finally {
      setSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className={styles.contactPage}>
        <div className={styles.success}>
          <div className={styles.successIcon}>✓</div>
          <h2 className={styles.successTitle}>Yêu cầu đã được gửi!</h2>
          <p className={styles.successMessage}>
            Đội ngũ hỗ trợ sẽ phản hồi bạn sớm nhất có thể.
            <br />
            Bạn sẽ nhận được thông báo qua email khi có cập nhật.
          </p>
          <button
            className={styles.backButton}
            onClick={() => navigate('/help')}
          >
            Quay về Trung tâm Trợ giúp
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.contactPage}>
      {/* Header */}
      <div className={styles.header}>
        <h1 className={styles.title}>Liên hệ Hỗ trợ</h1>
        <p className={styles.subtitle}>
          Gửi yêu cầu hỗ trợ của bạn và chúng tôi sẽ phản hồi sớm nhất
        </p>
      </div>

      {/* Contact Info */}
      <div className={styles.contactInfo}>
        <div className={styles.infoCard}>
          <span className={styles.infoIcon}>📧</span>
          <div>
            <strong>Email</strong>
            <p>support@example.com</p>
          </div>
        </div>
        <div className={styles.infoCard}>
          <span className={styles.infoIcon}>📞</span>
          <div>
            <strong>Hotline</strong>
            <p>1900 xxxx</p>
          </div>
        </div>
        <div className={styles.infoCard}>
          <span className={styles.infoIcon}>⏰</span>
          <div>
            <strong>Giờ làm việc</strong>
            <p>T2-T6: 8:00 - 17:30</p>
          </div>
        </div>
      </div>

      {/* Form */}
      <ContactForm onSubmit={handleSubmit} submitting={submitting} />
    </div>
  );
};
