import React from 'react';
import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { adminAccountsService } from '../../services/admin';
import type { AdminAccountListItem } from '../../services/admin';

function toListItem(detail: AdminAccountListItem): AdminAccountListItem {
  return detail;
}

/** SearchInput config — GET /admin/accounts filtered by companyId. */
export function createAdminAccountSearchConfig(
  companyId: string | undefined,
): SearchInputConfig<AdminAccountListItem> {
  return {
    api: {
      getItemKey: (item) => item.id,
      search: async ({ search, page, pageSize }) => {
        if (!companyId) {
          return { items: [], page: 1, totalPages: 1 };
        }
        const res = await adminAccountsService.getAccounts({
          companyId,
          search: search?.trim() || undefined,
          status: 'Active',
          page,
          pageSize,
        });
        const size = pageSize || 20;
        const totalPages = Math.max(1, Math.ceil((res.total ?? 0) / size));
        return {
          items: res.items,
          page: res.page,
          totalPages,
        };
      },
      getDetail: async (id) => {
        const detail = await adminAccountsService.getAccountDetail(id);
        return toListItem(detail);
      },
    },
    display: {
      getPrimaryDisplay: (item) => item.username,
      getSecondaryDisplay: (item) => item.fullName,
      getSingleDisplay: (item) => `${item.username} — ${item.fullName}`,
    },
    columns: [
      {
        key: 'username',
        variant: 'badge',
        width: '7rem',
        render: (item) => item.username,
      },
      {
        key: 'fullName',
        variant: 'primary',
        width: 'minmax(0, 1fr)',
        render: (item) => item.fullName,
      },
      {
        key: 'meta',
        variant: 'meta',
        render: (item) => (
          <>
            {item.email && (
              <span>
                <i className="fas fa-envelope" /> {item.email}
              </span>
            )}
            {item.role && (
              <span>
                <i className="fas fa-user-tag" /> {item.role}
              </span>
            )}
          </>
        ),
      },
    ],
    header: {
      columns: [
        { key: 'username', label: 'Username' },
        { key: 'fullName', label: 'Họ và tên' },
        { key: 'meta', label: 'Thông tin' },
      ],
    },
    texts: {
      empty: companyId ? 'Không tìm thấy tài khoản' : 'Chọn công ty trước',
      secondaryPlaceholder: 'Họ và tên',
    },
  };
}
