/**
 * SystemTab Component
 * Displays system and department-level configuration (read-only view)
 * Only accessible to Admin / Manager roles
 */

import React from 'react';
import { SystemSettings } from '../../../models/Settings';
import styles from './SystemTab.module.css';

interface SystemTabProps {
  systemSettings: SystemSettings;
}

const priorityMeta: Record<string, { label: string; badgeClass: string }> = {
  emergency: { label: 'Khẩn cấp', badgeClass: styles.priorityDanger },
  high:      { label: 'Cao',       badgeClass: styles.priorityWarning },
  medium:    { label: 'Trung bình', badgeClass: styles.priorityInfo },
  low:       { label: 'Thấp',       badgeClass: styles.prioritySecondary },
};

const formatMinutes = (minutes: number): string => {
  if (minutes < 60) return `${minutes} phút`;
  const hours = Math.floor(minutes / 60);
  const mins = minutes % 60;
  return mins > 0 ? `${hours} giờ ${mins} phút` : `${hours} giờ`;
};

export const SystemTab: React.FC<SystemTabProps> = ({ systemSettings }) => {
  const { general, sla, notifications, security } = systemSettings;

  return (
    <div className={styles.systemTab}>
      {/* Info Banner */}
      <div className={styles.infoBanner}>
        <i className="fas fa-building"></i>
        <div>
          <strong>Cấu hình bộ phận &amp; hệ thống</strong>
          <span> — Đây là cài đặt cấp hệ thống. Liên hệ Admin để thay đổi.</span>
        </div>
      </div>

      {/* General Settings */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className="fas fa-sliders-h"></i>
          <h3 className={styles.cardTitle}>Cài đặt chung</h3>
        </div>
        <div className={styles.cardBody}>
          <div className={styles.infoGrid}>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Tên hệ thống</span>
              <span className={styles.infoValue}>{general.systemName}</span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Múi giờ</span>
              <span className={styles.infoValue}>{general.timezone}</span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Ngôn ngữ mặc định</span>
              <span className={styles.infoValue}>
                {general.defaultLanguage === 'vi' ? '🇻🇳 Tiếng Việt' : '🇺🇸 English'}
              </span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Định dạng ngày</span>
              <span className={styles.infoValue}>{general.defaultDateFormat}</span>
            </div>
          </div>

          <div className={styles.togglesRow}>
            <div className={`${styles.toggleChip} ${general.autoAssignTasks ? styles.chipOn : styles.chipOff}`}>
              <i className={`fas ${general.autoAssignTasks ? 'fa-check-circle' : 'fa-circle'}`}></i>
              Tự động phân công công việc
            </div>
            <div className={`${styles.toggleChip} ${general.autoSendEmails ? styles.chipOn : styles.chipOff}`}>
              <i className={`fas ${general.autoSendEmails ? 'fa-check-circle' : 'fa-circle'}`}></i>
              Tự động gửi email thông báo
            </div>
            <div className={`${styles.toggleChip} ${general.maintenanceMode ? styles.chipWarn : styles.chipOff}`}>
              <i className={`fas ${general.maintenanceMode ? 'fa-tools' : 'fa-check-circle'}`}></i>
              Bảo trì: <strong>{general.maintenanceMode ? 'Đang bật' : 'Tắt'}</strong>
            </div>
          </div>
        </div>
      </div>

      {/* SLA Configuration */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className="fas fa-clock"></i>
          <h3 className={styles.cardTitle}>Cấu hình SLA theo mức độ ưu tiên</h3>
          <div className={`${styles.autoEscalateChip} ${sla.autoEscalate ? styles.chipOn : styles.chipOff}`}>
            <i className={`fas ${sla.autoEscalate ? 'fa-bolt' : 'fa-ban'}`}></i>
            Leo thang tự động: <strong>{sla.autoEscalate ? 'Bật' : 'Tắt'}</strong>
          </div>
        </div>
        <div className={styles.cardBody}>
          <div className={styles.tableWrapper}>
            <table className={styles.slaTable}>
              <thead>
                <tr>
                  <th>Mức độ</th>
                  <th><i className="fas fa-reply"></i> Phản hồi</th>
                  <th><i className="fas fa-check"></i> Giải quyết</th>
                  <th><i className="fas fa-bell"></i> Cảnh báo trước</th>
                </tr>
              </thead>
              <tbody>
                {sla.priorities.map((p) => {
                  const meta = priorityMeta[p.priority] ?? { label: p.priority, badgeClass: styles.prioritySecondary };
                  return (
                    <tr key={p.priority}>
                      <td>
                        <span className={`${styles.priorityBadge} ${meta.badgeClass}`}>
                          {meta.label}
                        </span>
                      </td>
                      <td>{formatMinutes(p.responseTime)}</td>
                      <td>{formatMinutes(p.resolutionTime)}</td>
                      <td>{formatMinutes(p.warningBefore)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Notification Channels */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className="fas fa-bell"></i>
          <h3 className={styles.cardTitle}>Kênh thông báo hệ thống</h3>
        </div>
        <div className={styles.cardBody}>
          <div className={styles.channelsGrid}>
            <div className={`${styles.channelCard} ${notifications.emailEnabled ? styles.channelActive : styles.channelInactive}`}>
              <i className="fas fa-envelope"></i>
              <span className={styles.channelName}>Email</span>
              <span className={styles.channelStatus}>{notifications.emailEnabled ? 'Bật' : 'Tắt'}</span>
              {notifications.emailEnabled && notifications.smtpHost && (
                <span className={styles.channelDetail}>{notifications.smtpHost}:{notifications.smtpPort}</span>
              )}
            </div>
            <div className={`${styles.channelCard} ${notifications.smsEnabled ? styles.channelActive : styles.channelInactive}`}>
              <i className="fas fa-sms"></i>
              <span className={styles.channelName}>SMS</span>
              <span className={styles.channelStatus}>{notifications.smsEnabled ? 'Bật' : 'Tắt'}</span>
              {notifications.smsEnabled && notifications.smsProvider && (
                <span className={styles.channelDetail}>{notifications.smsProvider}</span>
              )}
            </div>
            <div className={`${styles.channelCard} ${notifications.pushEnabled ? styles.channelActive : styles.channelInactive}`}>
              <i className="fas fa-mobile-alt"></i>
              <span className={styles.channelName}>Push</span>
              <span className={styles.channelStatus}>{notifications.pushEnabled ? 'Bật' : 'Tắt'}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Security Policy */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <i className="fas fa-shield-alt"></i>
          <h3 className={styles.cardTitle}>Chính sách bảo mật hệ thống</h3>
        </div>
        <div className={styles.cardBody}>
          <div className={styles.infoGrid}>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Độ dài mật khẩu tối thiểu</span>
              <span className={styles.infoValue}>{security.passwordMinLength} ký tự</span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Chu kỳ đổi mật khẩu</span>
              <span className={styles.infoValue}>{security.passwordExpiryDays} ngày</span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Đăng nhập sai tối đa</span>
              <span className={styles.infoValue}>{security.maxLoginAttempts} lần</span>
            </div>
            <div className={styles.infoItem}>
              <span className={styles.infoLabel}>Hết phiên đăng nhập</span>
              <span className={styles.infoValue}>{formatMinutes(security.sessionTimeout)}</span>
            </div>
          </div>

          <div className={styles.togglesRow}>
            {[
              { on: security.passwordRequireUppercase, label: 'Yêu cầu chữ hoa' },
              { on: security.passwordRequireLowercase, label: 'Yêu cầu chữ thường' },
              { on: security.passwordRequireNumbers,   label: 'Yêu cầu chữ số' },
              { on: security.passwordRequireSymbols,   label: 'Yêu cầu ký tự đặc biệt' },
            ].map((r) => (
              <div key={r.label} className={`${styles.toggleChip} ${r.on ? styles.chipOn : styles.chipOff}`}>
                <i className={`fas ${r.on ? 'fa-check-circle' : 'fa-times-circle'}`}></i>
                {r.label}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};
